// Extract inputs from webhook body
const category = $input.first().json.body.category;
const country = $input.first().json.body.country;
const filters = $input.first().json.body.filters || {};

// Build Google Maps search URL
const searchQuery = encodeURIComponent(`${category} in ${country}`);
const searchUrl = `https://www.google.com/maps/search/${searchQuery}`;

return [{
  json: {
    category,
    country,
    filters,
    searchUrl,
    searchQuery
  }
}];

