// Calculate ICP Score for each lead
const lead = $input.first().json;
let score = 0;

// Scoring rules from APEX spec
if (lead.email && lead.email.length > 3) score += 20;      // Has email
if (lead.phone && lead.phone.length > 5) score += 15;      // Has phone
if (lead.website && lead.website.length > 5) score += 15;   // Has website
if (lead.rating && lead.rating >= 4.0) score += 15;         // Rating 4+
